def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    ranges = []
    start = end = sorted_nums[0]

    for num in sorted_nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                ranges.append(str(start))
            else:
                ranges.append(f'{start}-{end}')
            start = end = num

    if start == end:
        ranges.append(str(start))
    else:
        ranges.append(f'{start}-{end}')

    return ','.join(ranges)
